}
.delay-d {
animation-delay: -0.67s;
}
.delay-e {
animation-delay: -0.83s;
}
.delay-f {
animation-delay: -1s;
}

@keyframes pulse {
0% {
opacity: 0.1;
}
30% {
opacity: 1;
}
100% {
opacity: 0.1;
}
}
